+void printWarningLocalGroupResized(const size_t local_work_size[]) {
+    std::cout << "[Warning] Thread-Block size got automatically resized: [" << local_work_size[0] << "," << local_work_size[1] << "," << local_work_size[2] << "]" << std::endl;
